arguments.file_text:
@typeparam TItem

<table>
    <thead>
        <tr>
            @HeaderTemplate
        </tr>
    </thead>
    <tbody>
        @if (Items is { Count: > 0 })
        {
            @foreach (var item in Items)
            {
                <tr @key="item" @onclick="() => OnRowClick.InvokeAsync(item)">
                    @if (RowTemplate is not null)
                    {
                        @RowTemplate(item)
                    }
                </tr>
            }
        }
        else
        {
            <tr>
                @if (EmptyTemplate is not null)
                {
                    @EmptyTemplate
                }
                else
                {
                    <td colspan="100">No items to display.</td>
                }
            </tr>
        }
    </tbody>
</table>

@code {
    [Parameter, EditorRequired] public IReadOnlyList<TItem> Items { get; set; } = [];
    [Parameter, EditorRequired] public RenderFragment HeaderTemplate { get; set; } = default!;
    [Parameter, EditorRequired] public RenderFragment<TItem> RowTemplate { get; set; } = default!;
    [Parameter] public RenderFragment? EmptyTemplate { get; set; }
    [Parameter] public EventCallback<TItem> OnRowClick { get; set; }
}

